import React, { useState, useEffect } from 'react';
import { ShoppingCart, MapPin, Box, UserCheck, Search, ChevronDown, Filter } from 'lucide-react';

const PanelCliente = () => {
  const [todasLasOfertas, setTodasLasOfertas] = useState([]);
  const [ofertasFiltradas, setOfertasFiltradas] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  
  // Mismos estados de ubicación del Home
  const [provincia] = useState('Tucumán');
  const [ciudad] = useState('San Miguel de Tucumán');
  const [zona, setZona] = useState('Todas las zonas');

  const zonasTucuman = ['Todas las zonas', 'Barrio Norte', 'Barrio Sur', 'Yerba Buena', 'Tafí Viejo', 'Concepción'];

  useEffect(() => {
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    let acumulador = [];

    locales.forEach(local => {
      const ofertasLocal = JSON.parse(localStorage.getItem(`ofertas-local-${local.id}`) || "[]");
      acumulador = [...acumulador, ...ofertasLocal.map(o => ({
        ...o,
        nombreLocal: local.nombre,
        coords: local.coords,
        zona: local.zona || 'Barrio Norte'
      }))];
    });

    setTodasLasOfertas(acumulador);
  }, []);

  // Lógica de filtrado idéntica al Home para mantener la consistencia
  useEffect(() => {
    let resultado = todasLasOfertas.filter(o => {
      const coincideBusqueda = o.producto.toLowerCase().includes(busqueda.toLowerCase());
      const coincideZona = zona === 'Todas las zonas' || o.zona === zona;
      return coincideBusqueda && coincideZona;
    });
    setOfertasFiltradas(resultado);
  }, [busqueda, zona, todasLasOfertas]);

  return (
    <div style={{ background: '#f1f5f9', minHeight: '100vh' }}>
      
      {/* REPLICAMOS EL HEADER DE FILTROS DEL HOME */}
      <div style={locationHeader}>
        <div style={locationBar}>
          <div style={locationItem}>
            <span style={labelUbi}>Provincia</span>
            <div style={selectorUbi}>{provincia} <ChevronDown size={14} /></div>
          </div>
          <div style={dividerV} />
          <div style={locationItem}>
            <span style={labelUbi}>Ciudad</span>
            <div style={selectorUbi}>{ciudad} <ChevronDown size={14} /></div>
          </div>
        </div>

        <div style={zonaWrapper}>
          <div style={zonaScroll}>
            {zonasTucuman.map(z => (
              <button 
                key={z} 
                onClick={() => setZona(z)}
                style={zona === z ? zonaBtnActive : zonaBtn}
              >
                {z}
              </button>
            ))}
          </div>
        </div>
      </div>

      <div style={{ padding: '20px 5%' }}>
        {/* BUSCADOR */}
        <div style={searchBox}>
          <Search size={20} color="#94a3b8" />
          <input 
            type="text" 
            placeholder="Buscar en mis ofertas..." 
            style={searchInput}
            onChange={(e) => setBusqueda(e.target.value)}
          />
          <Filter size={20} color="#e67e22" />
        </div>

        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', margin: '25px 0' }}>
          <h3 style={{ margin: 0 }}>Ofertas en {zona}</h3>
          <div style={countBadge}>{ofertasFiltradas.length} disponibles</div>
        </div>
        
        <div style={gridOfertas}>
          {ofertasFiltradas.length > 0 ? (
            ofertasFiltradas.map(o => (
              <div key={o.id} style={cardOferta}>
                <div style={badgeAhorro}>-{Math.round(((o.precioViejo - o.precioNuevo)/o.precioViejo)*100)}%</div>
                
                <div style={imgContainer}>
                   {o.imagen ? <img src={o.imagen} alt={o.producto} style={imgFull} /> : <Box size={40} color="#cbd5e1" />}
                </div>

                <div style={{ padding: '20px' }}>
                  <h4 style={titleStyle}>{o.producto}</h4>
                  
                  <div style={priceRow}>
                    <span style={pNew}>${o.precioNuevo}</span>
                    <span style={pOld}>${o.precioViejo}</span>
                  </div>

                  <div style={detailsGrid}>
                    <div style={detailTag}><Box size={14} /> Stock: {o.stock}</div>
                    <div style={detailTag}><UserCheck size={14} /> Límite: {o.limitePorCliente}</div>
                  </div>

                  <div style={divider} />

                  <div style={footerCard}>
                    <p style={localName}><MapPin size={14} color="#e67e22" /> {o.nombreLocal}</p>
                    <button style={btnAction}><ShoppingCart size={16} /> Reservar</button>
                  </div>
                </div>
              </div>
            ))
          ) : (
            <div style={emptyState}>No se encontraron ofertas con estos filtros.</div>
          )}
        </div>
      </div>
    </div>
  );
};

/* --- ESTILOS CONSISTENTES CON LA IDENTIDAD DE LA APP --- */
const locationHeader = { background: 'white', padding: '15px 5%', borderBottom: '1px solid #e2e8f0', position: 'sticky', top: 0, zIndex: 100 };
const locationBar = { display: 'flex', alignItems: 'center', background: '#f8fafc', borderRadius: '12px', padding: '10px 15px', marginBottom: '15px' };
const locationItem = { flex: 1 };
const labelUbi = { fontSize: '0.65rem', color: '#94a3b8', textTransform: 'uppercase', fontWeight: 'bold' };
const selectorUbi = { fontSize: '0.85rem', fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '5px' };
const dividerV = { width: '1px', height: '25px', background: '#e2e8f0', margin: '0 15px' };

const zonaWrapper = { overflow: 'hidden' };
const zonaScroll = { display: 'flex', gap: '10px', overflowX: 'auto', paddingBottom: '5px' };
const zonaBtn = { padding: '8px 16px', borderRadius: '20px', border: '1px solid #e2e8f0', background: 'white', whiteSpace: 'nowrap', cursor: 'pointer', fontSize: '0.8rem', color: '#64748b' };
